defmodule DevopsAutomationWeb.CommandController do
  use DevopsAutomationWeb, :controller

  alias DevopsAutomation.CommandService

  @doc """
  GET /api/commands
  Returns the list of available commands.
  """
  def index(conn, _params) do
    commands = CommandService.available_commands()
    json(conn, %{commands: commands})
  end

  @doc """
  POST /api/commands/execute
  Expects JSON body: {"command": "list_files", "args": ["/var/log"]}
  """
  def execute(conn, params) do
    with {:ok, command} <- extract_command(params),
         {:ok, args} <- extract_args(params) do
      case CommandService.execute(command, args) do
        {:ok, result} ->
          conn
          |> put_status(:ok)
          |> json(%{status: "success", data: result})

        {:error, %{output: output, exit_code: exit_code}} ->
          conn
          |> put_status(:unprocessable_entity)
          |> json(%{status: "error", output: output, exit_code: exit_code})

        {:error, reason} when is_binary(reason) ->
          conn
          |> put_status(:bad_request)
          |> json(%{status: "error", message: reason})
      end
    else
      {:error, reason} ->
        conn
        |> put_status(:bad_request)
        |> json(%{status: "error", message: reason})
    end
  end

  defp extract_command(%{"command" => command}) when is_binary(command), do: {:ok, command}
  defp extract_command(_), do: {:error, "Missing or invalid 'command' parameter. Must be a string."}

  defp extract_args(%{"args" => args}) when is_list(args) do
    if Enum.all?(args, &is_binary/1) do
      {:ok, args}
    else
      {:error, "All arguments must be strings."}
    end
  end

  defp extract_args(%{"args" => _}), do: {:error, "'args' must be a list of strings."}
  defp extract_args(_), do: {:ok, []}
end